fixed_code:
use std::mem::{size_of, transmute};

#[repr(C)]
struct A {
    x: u8,
}

#[repr(C)]
struct B {
    y: u16,
}

fn main() {
    let a = A { x: 42 };
    let b_ptr = &a as *const _ as *const B;
    // Correct alignment and size checks
    assert_eq!(size_of::<A>(), size_of::<B>());
    println!("b.y = {:x}", unsafe { (*b_ptr).y });
}
